// visitorRegistry maps visitor handle IDs to active Visitor instances.
// CGo does not allow passing Go function values as C function pointers;
// we use a numeric ID (stored in user_data) to look up the Visitor at callback time.
var (
	visitorRegistry  sync.Map
	visitorIDCounter atomic.Uint64
)

func registerVisitor(v Visitor) uintptr {
	id := uintptr(visitorIDCounter.Add(1))
	visitorRegistry.Store(id, v)
	return id
}

func unregisterVisitor(id uintptr) {
	visitorRegistry.Delete(id)
}

func lookupVisitor(id uintptr) (Visitor, bool) {
	v, ok := visitorRegistry.Load(id)
	if !ok {
		return nil, false
	}
	return v.(Visitor), true
}

func decodeNodeContext(ctxJSON *C.char) NodeContext {
	var ctx NodeContext
	if ctxJSON == nil {
		return ctx
	}
	_ = json.Unmarshal([]byte(C.GoString(ctxJSON)), &ctx)
	return ctx
}

func encodeVisitResult(r VisitResult, outResult **C.char) C.int32_t {
	// Encode the result as serde-native JSON so the Rust trait bridge's
	// serde_json deserialiser can decode it correctly.
	var jsonStr string
	switch r.Code {
	case 0:
		jsonStr = `"Continue"`
	case 1:
		if r.Value != nil {
			b, err := json.Marshal(*r.Value)
			if err != nil {
				b = []byte(`""`)
			}
			jsonStr = `{"Custom":` + string(b) + `}`
		} else {
			jsonStr = `{"Custom":""}`
		}
	case 2:
		jsonStr = `"Skip"`
	case 3:
		jsonStr = `"PreserveHtml"`
	case 4:
		if r.Value != nil {
			b, err := json.Marshal(*r.Value)
			if err != nil {
				b = []byte(`""`)
			}
			jsonStr = `{"Error":` + string(b) + `}`
		} else {
			jsonStr = `{"Error":""}`
		}
	default:
		jsonStr = `"Continue"`
	}
	*outResult = C.CString(jsonStr)
	return C.int32_t(r.Code)
}

func optGoString(p *C.char) *string {
	if p == nil {
		return nil
	}
	s := C.GoString(p)
	return &s
}

func decodeCellsJSON(cells *C.char) []string {
	if cells == nil {
		return nil
	}
	var result []string
	_ = json.Unmarshal([]byte(C.GoString(cells)), &result)
	return result
}

//export goVisitText
func goVisitText(userData unsafe.Pointer, ctx *C.char, text *C.char, outResult **C.char) C.int32_t {
	visitorID := uintptr(uintptr(userData))
	v, ok := lookupVisitor(visitorID)
	if !ok {
		return 0
	}
	nodeCtx := decodeNodeContext(ctx)
	goText := C.GoString(text)
	r := v.VisitText(nodeCtx, goText)
	return encodeVisitResult(r, outResult)
}

